int main() {
  int T; scanf("%d", &T);
  while (T--) {
    int N; scanf("%d", &N);
    int ans = 0;
    for (int i = 1; i <= N; i++) {
      for (int j = i + 1; j <= N; j++) {
        int sum1 = (i + j) * (j - i + 1) / 2;
        int sum2 = (N - j + 1 + N - i + 1) * (j - 1) / 2;
        if (sum1 == sum2) ans++;
      }
    }
    printf("%d\n", ans);
  }
  return 0;
}

