public class Main {
  public static void main(String[] args) {
    java.util.Scanner sc = new java.util.Scanner(System.in);
    int T = sc.nextInt();
    while (T-- > 0) {
      int N = sc.nextInt();
      int ans = 0;
      for (int i = 1; i <= N; i++) {
        for (int j = i + 1; j <= N; j++) {
          int sum1 = (i + j) * (j - i + 1) / 2;
          int sum2 = (N - j + 1 + N - i + 1) * (j - 1) / 2;
          if (sum1 == sum2) ans++;
        }
      }
      System.out.println(ans);
    }
  }
}

